  1→import type {
  2→  SDUIContext,
  3→  SDUIRule,
  4→  SDUILogicOperand,
  5→  SDUIVarOperator,
  6→  SDUILogicPrimitive,
  7→  SDUIExpressionOperand,
  8→  SDUIArithmeticExpression,
  9→} from '../models';
 10→import { resolveContextPath } from './interpolation';
 11→
 12→const MAX_DEPTH = 20;
 13→
 14→const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);
 15→const ARITHMETIC_OPS = new Set(['+', '-', '*', '/', 'min', 'max']);
 16→
 17→function isVarOperator(operand: unknown): operand is SDUIVarOperator {
 18→  return (
 19→    operand !== null &&
 20→    typeof operand === 'object' &&
 21→    'var' in operand &&
 22→    typeof (operand as SDUIVarOperator).var === 'string'
 23→  );
 24→}
 25→
 26→function isPrimitive(value: unknown): value is SDUILogicPrimitive {
 27→  return (
 28→    value === null ||
 29→    typeof value === 'string' ||
 30→    typeof value === 'number' ||
 31→    typeof value === 'boolean'
 32→  );
 33→}
 34→
 35→function isArithmeticExpression(value: unknown): value is SDUIArithmeticExpression {
 36→  if (!value || typeof value !== 'object') return false;
 37→  const keys = Object.keys(value);
 38→  return keys.length === 1 && ARITHMETIC_OPS.has(keys[0]);
 39→}
 40→
 41→function resolveExpressionOperand(
 42→  operand: SDUIExpressionOperand,
 43→  context: SDUIContext,
 44→  depth: number,
 45→): SDUILogicPrimitive {
 46→  if (isPrimitive(operand)) return operand;
 47→  if (isVarOperator(operand)) {
 48→    const resolved = resolveContextPath(context, (operand as SDUIVarOperator).var);
 49→    if (isPrimitive(resolved)) return resolved;
 50→    return null;
 51→  }
 52→  if (isArithmeticExpression(operand)) {
 53→    return computeArithmetic(operand, context, depth + 1);
 54→  }
 55→  return evaluate(operand as SDUIRule, context, depth + 1);
 56→}
 57→
 58→function toNumber(value: SDUILogicPrimitive): number | null {
 59→  if (typeof value === 'number') return value;
 60→  if (typeof value === 'string') {
 61→    const n = Number(value);
 62→    return Number.isFinite(n) ? n : null;
 63→  }
 64→  return null;
 65→}
 66→
 67→function computeArithmetic(
 68→  expr: SDUIArithmeticExpression,
 69→  context: SDUIContext,
 70→  depth: number,
 71→): number {
 72→  if (depth > MAX_DEPTH) return 0;
 73→
 74→  const keys = Object.keys(expr);
 75→  if (keys.length === 0) return 0;
 76→
 77→  const operator = keys[0];
 78→  const operands = (expr as Record<string, unknown>)[operator];
 79→  if (!Array.isArray(operands) || operands.length === 0) return 0;
 80→
 81→  const resolved = operands.map(op =>
 82→    toNumber(resolveExpressionOperand(op as SDUIExpressionOperand, context, depth)),
 83→  );
 84→
 85→  if (resolved.some(v => v === null)) return 0;
 86→  const nums = resolved as number[];
 87→
 88→  switch (operator) {
 89→    case '+':
 90→      return nums.reduce((a, b) => a + b, 0);
 91→    case '-':
 92→      if (nums.length !== 2) return 0;
 93→      return nums[0] - nums[1];
 94→    case '*':
 95→      return nums.reduce((a, b) => a * b, 1);
 96→    case '/':
 97→      if (nums.length !== 2) return 0;
 98→      if (nums[1] === 0) return 0;
 99→      return nums[0] / nums[1];
100→    case 'min':
101→      return Math.min(...nums);
102→    case 'max':
103→      return Math.max(...nums);
104→    default:
105→      return 0;
106→  }
107→}
108→
109→function resolveOperand(
110→  operand: SDUILogicOperand,
111→  context: SDUIContext,
112→  depth: number,
113→): SDUILogicPrimitive {
114→  if (isPrimitive(operand)) return operand;
115→  if (isVarOperator(operand)) {
116→    const resolved = resolveContextPath(context, (operand as SDUIVarOperator).var);
117→    if (isPrimitive(resolved)) return resolved;
118→    return null;
119→  }
120→  if (isArithmeticExpression(operand)) {
121→    return computeArithmetic(operand as SDUIArithmeticExpression, context, depth + 1);
122→  }
123→  return evaluate(operand as SDUIRule, context, depth + 1);
124→}
125→
126→function evaluateComparison(
127→  operator: string,
128→  operands: [SDUILogicOperand, SDUILogicOperand],
129→  context: SDUIContext,
130→  depth: number,
131→): boolean {
132→  const left = resolveOperand(operands[0], context, depth);
133→  const right = resolveOperand(operands[1], context, depth);
134→
135→  switch (operator) {
136→    case '==':
137→      return left == right; // eslint-disable-line eqeqeq
138→    case '!=':
139→      return left != right; // eslint-disable-line eqeqeq
140→    case '>':
141→      if (typeof left !== 'number' || typeof right !== 'number') return false;
142→      return left > right;
143→    case '<':
144→      if (typeof left !== 'number' || typeof right !== 'number') return false;
145→      return left < right;
146→    case '>=':
147→      if (typeof left !== 'number' || typeof right !== 'number') return false;
148→      return left >= right;
149→    case '<=':
150→      if (typeof left !== 'number' || typeof right !== 'number') return false;
151→      return left <= right;
152→    default:
153→      return false;
154→  }
155→}
156→
157→function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
158→  if (!rule || typeof rule !== 'object') return false;
159→  if (depth > MAX_DEPTH) return false;
160→
161→  const keys = Object.keys(rule);
162→  if (keys.length === 0) return false;
163→
164→  const operator = keys[0];
165→  const operands = (rule as Record<string, unknown>)[operator];
166→
167→  if (operator === 'and') {
168→    if (!Array.isArray(operands)) return false;
169→    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
170→  }
171→
172→  if (operator === 'or') {
173→    if (!Array.isArray(operands)) return false;
174→    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
175→  }
176→
177→  if (operator === '!') {
178→    const inner = Array.isArray(operands) ? operands[0] : operands;
179→    return !evaluate(inner as SDUIRule, context, depth + 1);
180→  }
181→
182→  if (COMPARISON_OPS.has(operator)) {
183→    if (!Array.isArray(operands) || operands.length !== 2) return false;
184→    return evaluateComparison(
185→      operator,
186→      operands as [SDUILogicOperand, SDUILogicOperand],
187→      context,
188→      depth,
189→    );
190→  }
191→
192→  return false;
193→}
194→
195→export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
196→  return evaluate(rule, context, 0);
197→}
198→
199→export function evaluateExpression(
200→  expr: SDUIArithmeticExpression | SDUIExpressionOperand,
201→  context: SDUIContext,
202→): number | string | boolean | null {
203→  if (isPrimitive(expr)) return expr;
204→  if (isVarOperator(expr)) {
205→    const resolved = resolveContextPath(context, (expr as SDUIVarOperator).var);
206→    if (isPrimitive(resolved)) return resolved;
207→    return null;
208→  }
209→  if (isArithmeticExpression(expr)) {
210→    return computeArithmetic(expr, context, 0);
211→  }
212→  return evaluate(expr as SDUIRule, context, 0);
213→}
